module top_module(in, enable, clear, clk, out);input [5:0] in;
  input enable;
  input clear;
  input clk;
  output [5:0] out;

  reg [5:0] registers;

  always @ (posedge clk) begin
    if(enable && clear) begin
      registers = 6'b000000;
    end

    else if(enable) begin
      registers <= in;
    end
  end

  assign out = registers;

endmodule
